using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;
using System;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelper
    {
        public static SchoolContext CreateInMemoryContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext(string dbName = null)
        {
            var context = CreateInMemoryContext(dbName);
            DbInitializer.Initialize(context);
            return context;
        }
    }
}

using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        private class ConcretePerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = "John" };
            Assert.Equal("Smith, John", person.FullName);
        }

        [Fact]
        public void FullName_HandlesNullLastName()
        {
            var person = new ConcretePerson { LastName = null, FirstMidName = "John" };
            Assert.Equal(", John", person.FullName);
        }

        [Fact]
        public void FullName_HandlesNullFirstName()
        {
            var person = new ConcretePerson { LastName = "Smith", FirstMidName = null };
            Assert.Equal("Smith, ", person.FullName);
        }

        [Fact]
        public void ID_DefaultsToZero()
        {
            var person = new ConcretePerson();
            Assert.Equal(0, person.ID);
        }

        [Fact]
        public void Properties_CanBeSetAndGet()
        {
            var person = new ConcretePerson
            {
                ID = 42,
                LastName = "Doe",
                FirstMidName = "Jane"
            };

            Assert.Equal(42, person.ID);
            Assert.Equal("Doe", person.LastName);
            Assert.Equal("Jane", person.FirstMidName);
        }
    }
}

using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class StudentTests
    {
        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student();
            Assert.IsAssignableFrom<Person>(student);
        }

        [Fact]
        public void EnrollmentDate_CanBeSetAndGet()
        {
            var date = new DateTime(2024, 9, 1);
            var student = new Student { EnrollmentDate = date };
            Assert.Equal(date, student.EnrollmentDate);
        }

        [Fact]
        public void Enrollments_CanBeInitialized()
        {
            var student = new Student
            {
                Enrollments = new List<Enrollment>
                {
                    new Enrollment { EnrollmentID = 1 },
                    new Enrollment { EnrollmentID = 2 }
                }
            };

            Assert.Equal(2, student.Enrollments.Count);
        }

        [Fact]
        public void Enrollments_DefaultsToNull()
        {
            var student = new Student();
            Assert.Null(student.Enrollments);
        }

        [Fact]
        public void FullName_InheritedFromPerson()
        {
            var student = new Student { LastName = "Alexander", FirstMidName = "Carson" };
            Assert.Equal("Alexander, Carson", student.FullName);
        }

        [Fact]
        public void AllProperties_CanBeSet()
        {
            var date = new DateTime(2020, 1, 15);
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = date
            };

            Assert.Equal(1, student.ID);
            Assert.Equal("Test", student.LastName);
            Assert.Equal("Student", student.FirstMidName);
            Assert.Equal(date, student.EnrollmentDate);
        }
    }
}

