using ContosoUniversity.Models;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class CourseTests
    {
        [Fact]
        public void Properties_CanBeSetAndGet()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1,
                TeachingMaterialImagePath = "/Uploads/test.jpg"
            };

            Assert.Equal(1050, course.CourseID);
            Assert.Equal("Chemistry", course.Title);
            Assert.Equal(3, course.Credits);
            Assert.Equal(1, course.DepartmentID);
            Assert.Equal("/Uploads/test.jpg", course.TeachingMaterialImagePath);
        }

        [Fact]
        public void Department_NavigationProperty()
        {
            var dept = new Department { DepartmentID = 1, Name = "Engineering" };
            var course = new Course { Department = dept };
            Assert.Equal("Engineering", course.Department.Name);
        }

        [Fact]
        public void Enrollments_NavigationProperty()
        {
