using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class InstructorTests
    {
        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor();
            Assert.IsAssignableFrom<Person>(instructor);
        }

        [Fact]
        public void HireDate_CanBeSetAndGet()
        {
            var date = new DateTime(2000, 3, 15);
            var instructor = new Instructor { HireDate = date };
            Assert.Equal(date, instructor.HireDate);
        }

        [Fact]
        public void CourseAssignments_CanBeInitialized()
        {
            var instructor = new Instructor
            {
                CourseAssignments = new List<CourseAssignment>
                {
                    new CourseAssignment { CourseID = 1 },
                    new CourseAssignment { CourseID = 2 }
                }
            };

            Assert.Equal(2, instructor.CourseAssignments.Count);
        }

        [Fact]
        public void OfficeAssignment_CanBeSet()
        {
            var office = new OfficeAssignment { Location = "Room 101" };
            var instructor = new Instructor { OfficeAssignment = office };
            Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
        }

        [Fact]
        public void OfficeAssignment_DefaultsToNull()
        {
            var instructor = new Instructor();
            Assert.Null(instructor.OfficeAssignment);
        }

        [Fact]
        public void FullName_InheritedFromPerson()
        {
            var instructor = new Instructor { LastName = "Abercrombie", FirstMidName = "Kim" };
            Assert.Equal("Abercrombie, Kim", instructor.FullName);
        }

        [Fact]
        public void AllProperties_CanBeSet()
        {
            var date = new DateTime(1998, 7, 1);
            var instructor = new Instructor
            {
                ID = 5,
                LastName = "Harui",
                FirstMidName = "Roger",
                HireDate = date
            };

            Assert.Equal(5, instructor.ID);
            Assert.Equal("Harui", instructor.LastName);
            Assert.Equal("Roger", instructor.FirstMidName);
            Assert.Equal(date, instructor.HireDate);
        }
    }
}

