using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class DepartmentTests
    {
        [Fact]
        public void Properties_CanBeSetAndGet()
        {
            var date = new DateTime(2007, 9, 1);
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000m,
                StartDate = date,
                InstructorID = 3
            };

            Assert.Equal(1, dept.DepartmentID);
            Assert.Equal("Engineering", dept.Name);
            Assert.Equal(350000m, dept.Budget);
            Assert.Equal(date, dept.StartDate);
            Assert.Equal(3, dept.InstructorID);
        }

        [Fact]
        public void InstructorID_IsNullable()
        {
            var dept = new Department { InstructorID = null };
            Assert.Null(dept.InstructorID);
        }

        [Fact]
        public void RowVersion_CanBeSet()
        {
            var version = new byte[] { 0, 0, 0, 0, 0, 0, 7, 209 };
            var dept = new Department { RowVersion = version };
            Assert.Equal(version, dept.RowVersion);
        }

        [Fact]
        public void Administrator_NavigationProperty()
        {
            var instructor = new Instructor { LastName = "Harui", FirstMidName = "Roger" };
            var dept = new Department { Administrator = instructor };
            Assert.Equal("Harui, Roger", dept.Administrator.FullName);
        }

        [Fact]
        public void Courses_NavigationProperty()
        {
            var dept = new Department
            {
                Courses = new List<Course>
                {
                    new Course { CourseID = 1050, Title = "Chemistry" },
                    new Course { CourseID = 1045, Title = "Calculus" }
                }
            };

            Assert.Equal(2, dept.Courses.Count);
        }

        [Fact]
        public void RowVersion_DefaultsToNull()
        {
            var dept = new Department();
            Assert.Null(dept.RowVersion);
        }
    }
}

