using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class EnrollmentTests
    {
        [Fact]
        public void Properties_CanBeSetAndGet()
        {
            var enrollment = new Enrollment
            {
                EnrollmentID = 1,
                CourseID = 1050,
                StudentID = 1,
                Grade = Grade.A
            };

            Assert.Equal(1, enrollment.EnrollmentID);
            Assert.Equal(1050, enrollment.CourseID);
            Assert.Equal(1, enrollment.StudentID);
            Assert.Equal(Grade.A, enrollment.Grade);
        }

        [Fact]
        public void Grade_IsNullable()
        {
            var enrollment = new Enrollment { Grade = null };
            Assert.Null(enrollment.Grade);
        }

        [Theory]
        [InlineData(Grade.A)]
        [InlineData(Grade.B)]
        [InlineData(Grade.C)]
        [InlineData(Grade.D)]
        [InlineData(Grade.F)]
        public void Grade_AllValuesValid(Grade grade)
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }

        [Fact]
        public void Course_NavigationProperty()
        {
            var course = new Course { CourseID = 1050, Title = "Chemistry" };
            var enrollment = new Enrollment { Course = course };
            Assert.Equal("Chemistry", enrollment.Course.Title);
        }

        [Fact]
        public void Student_NavigationProperty()
        {
            var student = new Student { LastName = "Alexander", FirstMidName = "Carson" };
            var enrollment = new Enrollment { Student = student };
            Assert.Equal("Alexander, Carson", enrollment.Student.FullName);
        }

        [Fact]
        public void NavigationProperties_DefaultToNull()
        {
            var enrollment = new Enrollment();
            Assert.Null(enrollment.Course);
            Assert.Null(enrollment.Student);
            Assert.Null(enrollment.Grade);
        }

        [Fact]
        public void GradeEnum_HasCorrectValues()
        {
            Assert.Equal(0, (int)Grade.A);
            Assert.Equal(1, (int)Grade.B);
            Assert.Equal(2, (int)Grade.C);
            Assert.Equal(3, (int)Grade.D);
            Assert.Equal(4, (int)Grade.F);
        }
    }
}

