using ContosoUniversity.Models;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class NotificationTests
    {
        [Fact]
        public void Properties_CanBeSetAndGet()
        {
            var now = DateTime.Now;
            var notification = new Notification
            {
                Id = 1,
                EntityType = "Student",
                EntityId = "42",
                Operation = "CREATE",
                Message = "New Student has been created",
                CreatedAt = now,
                CreatedBy = "System",
                IsRead = false,
                ReadAt = null
            };

            Assert.Equal(1, notification.Id);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("New Student has been created", notification.Message);
            Assert.Equal(now, notification.CreatedAt);
            Assert.Equal("System", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void IsRead_DefaultsToFalse()
        {
            var notification = new Notification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void ReadAt_IsNullable()
        {
            var notification = new Notification { ReadAt = null };
            Assert.Null(notification.ReadAt);

            var readTime = DateTime.Now;
            notification.ReadAt = readTime;
            Assert.Equal(readTime, notification.ReadAt);
        }

        [Fact]
        public void EntityOperation_HasCorrectValues()
        {
            Assert.Equal(0, (int)EntityOperation.CREATE);
            Assert.Equal(1, (int)EntityOperation.UPDATE);
            Assert.Equal(2, (int)EntityOperation.DELETE);
        }

        [Fact]
        public void EntityOperation_AllValuesConvertToString()
        {
            Assert.Equal("CREATE", EntityOperation.CREATE.ToString());
            Assert.Equal("UPDATE", EntityOperation.UPDATE.ToString());
            Assert.Equal("DELETE", EntityOperation.DELETE.ToString());
        }
    }
}

