using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using System;
using System.Collections.Generic;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class ViewModelTests
    {
        [Fact]
        public void AssignedCourseData_Properties()
        {
            var data = new AssignedCourseData
            {
                CourseID = 1050,
                Title = "Chemistry",
                Assigned = true
            };

            Assert.Equal(1050, data.CourseID);
            Assert.Equal("Chemistry", data.Title);
            Assert.True(data.Assigned);
        }

        [Fact]
        public void AssignedCourseData_AssignedDefaultsFalse()
        {
            var data = new AssignedCourseData();
            Assert.False(data.Assigned);
        }

        [Fact]
        public void EnrollmentDateGroup_Properties()
        {
            var date = new DateTime(2010, 9, 1);
            var group = new EnrollmentDateGroup
            {
                EnrollmentDate = date,
                StudentCount = 5
            };

            Assert.Equal(date, group.EnrollmentDate);
            Assert.Equal(5, group.StudentCount);
        }

        [Fact]
        public void EnrollmentDateGroup_NullableDate()
        {
            var group = new EnrollmentDateGroup { EnrollmentDate = null };
            Assert.Null(group.EnrollmentDate);
        }

        [Fact]
        public void InstructorIndexData_Properties()
        {
            var instructors = new List<Instructor>
            {
                new Instructor { LastName = "A", FirstMidName = "B" }
            };
            var courses = new List<Course>
            {
                new Course { CourseID = 1, Title = "Test" }
            };
            var enrollments = new List<Enrollment>
            {
                new Enrollment { EnrollmentID = 1 }
            };

            var data = new InstructorIndexData
            {
                Instructors = instructors,
                Courses = courses,
                Enrollments = enrollments
            };

            Assert.Single(data.Instructors);
            Assert.Single(data.Courses);
            Assert.Single(data.Enrollments);
        }

        [Fact]
        public void InstructorIndexData_NullCollections()
        {
            var data = new InstructorIndexData();
            Assert.Null(data.Instructors);
            Assert.Null(data.Courses);
            Assert.Null(data.Enrollments);
        }
    }
}

