using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);
            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);
            Assert.Equal(3, list.Count);
            Assert.Contains(1, list);
            Assert.Contains(2, list);
            Assert.Contains(3, list);
        }

        [Fact]
        public void HasPreviousPage_FalseOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_TrueOnSecondPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_TrueWhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
        }

        [Fact]
        public void HasNextPage_FalseOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.False(list.HasNextPage); // TotalPages = 2, PageIndex = 2
        }

        [Fact]
        public void HasNextPage_FalseWhenSinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
            Assert.False(list.HasNextPage); // TotalPages = 1
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var list = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(10, list.Count);
            Assert.Equal(11, list.First());
            Assert.Equal(20, list.Last());
            Assert.Equal(2, list.PageIndex);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void Create_FirstPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var list = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(10, list.Count);
            Assert.Equal(1, list.First());
            Assert.Equal(10, list.Last());
        }

        [Fact]
        public void Create_LastPage_PartialItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();
            var list = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(5, list.Count);
            Assert.Equal(21, list.First());
            Assert.Equal(25, list.Last());
        }

        [Fact]
        public void Create_SingleItem()
        {
            var source = new[] { 42 }.AsQueryable();
            var list = PaginatedList<int>.Create(source, 1, 10);

            Assert.Single(list);
            Assert.Equal(42, list.First());
            Assert.Equal(1, list.TotalPages);
            Assert.False(list.HasPreviousPage);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_EmptySource()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var list = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(list);
            Assert.Equal(0, list.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 5);
            Assert.Equal(4, list.TotalPages); // 20/5 = 4 exactly
        }

        [Fact]
        public void TotalPages_WithRemainder()
        {
            var list = new PaginatedList<int>(new List<int>(), 21, 1, 5);
            Assert.Equal(5, list.TotalPages); // ceil(21/5) = 5
        }

        [Fact]
        public void Create_WorksWithStringType()
        {
            var source = new[] { "a", "b", "c", "d", "e" }.AsQueryable();
            var list = PaginatedList<string>.Create(source, 1, 3);

            Assert.Equal(3, list.Count);
            Assert.Equal("a", list[0]);
            Assert.Equal("b", list[1]);
            Assert.Equal("c", list[2]);
            Assert.Equal(2, list.TotalPages);
        }
    }
}

