{"file_text": "using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover messages from the static queue (shared across tests)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "System");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Course 'Chemistry' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE, "System");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Student (ID: 42) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Department", "1", "Engineering", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Department 'Engineering' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            _service.SendNotification("Instructor", "5", "Roger Harui", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor 'Roger Harui' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNullWhenEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsFIFOOrder()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
            Assert.Equal("Department", third.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.NotNull(first);
            Assert.Null(second);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            var ex = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_Calls5ParamOverload()
        {
            _service.SendNotification("Instructor", "10", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Instructor (ID: 10) has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_WithNullDisplayName_UsesIdBased()
        {
            _service.SendNotification("Student", "5", null, EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_WithEmptyDisplayName_UsesIdBased()
        {
            _service.SendNotification("Student", "5", "", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdBased()
        {
            _service.SendNotification("Student", "5", "   ", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 5", notification.Message);
        }

        [Fact]
        public void SendNotification_MultipleNotifications_AllReceivable()
        {
            for (int i = 0; i < 20; i++)
            {
                _service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            var received = new List<Notification>();
            Notification n;
            while ((n = _service.ReceiveNotification()) != null)
            {
                received.Add(n);
            }

            Assert.Equal(20, received.Count);
        }
    }
}
