        public void Initialize_DoesNotReseedWhenDataExists()
        {
            using var context = TestHelper.CreateSeededContext();

            // Call Initialize again
            DbInitializer.Initialize(context);

            // Counts should remain the same
            Assert.Equal(8, context.Students.Count());
            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_StudentNamesAreCorrect()
        {
            using var context = TestHelper.CreateSeededContext();
            var lastNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            Assert.Contains("Alexander", lastNames);
            Assert.Contains("Alonso", lastNames);
            Assert.Contains("Anand", lastNames);
            Assert.Contains("Barzdukas", lastNames);
            Assert.Contains("Li", lastNames);
            Assert.Contains("Justice", lastNames);
            Assert.Contains("Norman", lastNames);
            Assert.Contains("Olivetto", lastNames);
        }

        [Fact]
        public void Initialize_DepartmentNamesAreCorrect()
        {
            using var context = TestHelper.CreateSeededContext();
            var names = context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
            Assert.Equal(new[] { "Economics", "Engineering", "English", "Mathematics" }, names);
        }

        [Fact]
        public void Initialize_CourseCreditsAreWithinRange()
        {
            using var context = TestHelper.CreateSeededContext();
            var credits = context.Courses.Select(c => c.Credits).ToList();
            Assert.All(credits, c => Assert.InRange(c, 0, 5));
        }

        [Fact]
        public void Initialize_AllDepartmentsHaveAdministrators()
        {
            using var context = TestHelper.CreateSeededContext();
            var departments = context.Departments.ToList();
            Assert.All(departments, d => Assert.NotNull(d.InstructorID));
        }

        [Fact]
        public void Initialize_EnrollmentsHaveValidReferences()
        {
            using var context = TestHelper.CreateSeededContext();
            var enrollments = context.Enrollments.ToList();
            var studentIds = context.Students.Select(s => s.ID).ToHashSet();
            var courseIds = context.Courses.Select(c => c.CourseID).ToHashSet();

            Assert.All(enrollments, e =>
            {
                Assert.Contains(e.StudentID, studentIds);
                Assert.Contains(e.CourseID, courseIds);
            });
        }
    }
}
