            Assert.IsType<Course>(result.Model);
        }

        // --- DeleteConfirmed (POST) ---

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var courseId = _context.Courses.First().CourseID;
            // Remove enrollments and assignments first
            var enrollments = _context.Enrollments.Where(e => e.CourseID == courseId).ToList();
            _context.Enrollments.RemoveRange(enrollments);
            var assignments = _context.CourseAssignments.Where(ca => ca.CourseID == courseId).ToList();
            _context.CourseAssignments.RemoveRange(assignments);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(courseId);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.DoesNotContain(_context.Courses, c => c.CourseID == courseId);
        }

        // --- Helper ---

        private static IFormFile CreateMockFormFile(string fileName, long length)
        {
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(_ => { });
            return mockFile.Object;
        }
    }
