{"file_text": "using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.Single();
            Assert.Equal("Test", retrieved.LastName);
            Assert.Equal("Student", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = DateTime.Today
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.Single();
            Assert.Equal("Test", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000m,
                StartDate = DateTime.Today
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 9999,
                Title = "TestCourse",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.Include(c => c.Department).Single();
            Assert.Equal("TestCourse", retrieved.Title);
            Assert.Equal("TestDept", retrieved.Department.Name);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 200000m,
                StartDate = new DateTime(2020, 1, 1)
            };

            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments.Single();
            Assert.Equal("TestDept", retrieved.Name);
            Assert.Equal(200000m, retrieved.Budget);
        }

        [Fact]
        public void CanCreateEnrollmentWithRelationships()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "EnrollTest",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today
            };
            context.Students.Add(student);

            var dept = new Department
            {
                Name = "Dept",
                Budget = 100000m,
                StartDate = DateTime.Today
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1111,
                Title = "Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            var retrieved = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .Single();
            Assert.Equal("EnrollTest", retrieved.Student.LastName);
            Assert.Equal("Course", retrieved.Course.Title);
            Assert.Equal(Grade.A, retrieved.Grade);
        }

        [Fact]
        public void CanAddOfficeAssignment()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Today
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            context.OfficeAssignments.Add(office);
            context.SaveChanges();

            var retrieved = context.OfficeAssignments
                .Include(o => o.Instructor)
                .Single();
            Assert.Equal("Room 101", retrieved.Location);
            Assert.Equal("Office", retrieved.Instructor.LastName);
        }

        [Fact]
        public void CanCreateCourseAssignment()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var instructor = new Instructor
            {
                LastName = "Assign",
                FirstMidName = "Test",
                HireDate = DateTime.Today
            };
            context.Instructors.Add(instructor);

            var dept = new Department
            {
                Name = "Dept",
                Budget = 100000m,
                StartDate = DateTime.Today
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 2222,
                Title = "AssignCourse",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            context.CourseAssignments.Add(assignment);
            context.SaveChanges();

            var retrieved = context.CourseAssignments
                .Include(ca => ca.Instructor)
                .Include(ca => ca.Course)
                .Single();
            Assert.Equal("Assign", retrieved.Instructor.LastName);
            Assert.Equal("AssignCourse", retrieved.Course.Title);
        }

        [Fact]
        public void CanAddNotification()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.Single();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("CREATE", retrieved.Operation);
        }

        [Fact]
        public void AllDbSetsAreAccessible()
        {
            using var context = TestHelper.CreateInMemoryContext();
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.People);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Notifications);
        }
    }
}
