using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new StudentsController(_context);

            // Setup required controller context
            var httpContext = new DefaultHttpContext();
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = httpContext
            };
            _controller.TempData = new TempDataDictionary(httpContext, new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        }

        public void Dispose()
        {
            _controller.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_ReturnsPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            Assert.IsType<PaginatedList<Student>>(result.Model);
        }

        [Fact]
        public void Index_DefaultSortsAscendingByLastName()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var names = model.Select(s => s.LastName).ToList();
            var sorted = names.OrderBy(n => n).ToList();
            Assert.Equal(sorted, names);
        }

        [Fact]
        public void Index_SortsByNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var names = model.Select(s => s.LastName).ToList();
            var sorted = names.OrderByDescending(n => n).ToList();
            Assert.Equal(sorted, names);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sorted = dates.OrderBy(d => d).ToList();
            Assert.Equal(sorted, dates);
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            var dates = model.Select(s => s.EnrollmentDate).ToList();
            var sorted = dates.OrderByDescending(d => d).ToList();
            Assert.Equal(sorted, dates);
        }

        [Fact]
        public void Index_FiltersStudentsBySearchString()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_FiltersStudentsByFirstName()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchStringResetsPageTo1()
        {
            var result = _controller.Index(null, null, "Li", null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_UsesCurrentFilterWhenSearchStringIsNull()
        {
            var result = _controller.Index(null, "Norman", null, null) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Single(model);
            Assert.Equal("Norman", model.First().LastName);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            _controller.Index("Date", null, "test", null);

            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }

        [Fact]
        public void Index_DefaultSortParms()
        {
            _controller.Index(null, null, null, null);

            Assert.Null(_controller.ViewBag.CurrentSort);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_RespectsPageNumber()
        {
            // Add more students to make multiple pages
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    LastName = $"ZZZ{i:D2}",
                    FirstMidName = "Test",
                    EnrollmentDate = DateTime.Today
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 2) as ViewResult;
            var model = result.Model as PaginatedList<Student>;

            Assert.Equal(2, model.PageIndex);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewResult()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Details(studentId);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudentWithEnrollments()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Details(studentId) as ViewResult;
            var student = Assert.IsType<Student>(result.Model);
            Assert.NotNull(student.Enrollments);
        }

        // --- Create (GET) ---

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create();
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Get_ReturnsStudentWithTodaysDate()
        {
            var result = _controller.Create() as ViewResult;
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        // --- Create (POST) ---

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2024, 9, 1)
            };

            var result = _controller.Create(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_SavestoDatabase()
        {
            var student = new Student
            {
                LastName = "SaveTest",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2024, 9, 1)
            };

            _controller.Create(student);
            Assert.Contains(_context.Students, s => s.LastName == "SaveTest");
        }

        [Fact]
        public void Create_Post_MinDateValue_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);
            Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_DateBefore1753_AddsModelError()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            var result = _controller.Create(student);
            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                LastName = "",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2024, 9, 1)
            };

            var result = _controller.Create(student);
            Assert.IsType<ViewResult>(result);
        }

        // --- Edit (GET) ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var student = _context.Students.First();
            var result = _controller.Edit(student.ID) as ViewResult;
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit (POST) ---

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.AsNoTracking().First();
            student.LastName = "UpdatedName";

            var result = _controller.Edit(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_MinDateValue_AddsModelError()
        {
            var student = _context.Students.AsNoTracking().First();
            student.EnrollmentDate = DateTime.MinValue;

            var result = _controller.Edit(student);
            Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = _context.Students.AsNoTracking().First();

            var result = _controller.Edit(student);
            Assert.IsType<ViewResult>(result);
        }

        // --- Delete (GET) ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Delete(studentId);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed (POST) ---

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var student = _context.Students.First();
            var id = student.ID;

            var result = _controller.DeleteConfirmed(id);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.DoesNotContain(_context.Students, s => s.ID == id);
        }
    }
}

