using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new DepartmentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Equal(4, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var result = _controller.Details(deptId) as ViewResult;
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(deptId, model.DepartmentID);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create (GET) ---

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create();
            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Create (POST) ---

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = new Department
            {
                Name = "Physics",
                Budget = 250000m,
                StartDate = new DateTime(2020, 9, 1),
                InstructorID = _context.Instructors.First().ID
            };

            var result = _controller.Create(dept);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidDepartment_SavesToDatabase()
        {
            var dept = new Department
            {
                Name = "Biology",
                Budget = 200000m,
                StartDate = new DateTime(2020, 9, 1),
                InstructorID = _context.Instructors.First().ID
            };

            _controller.Create(dept);
            Assert.Contains(_context.Departments, d => d.Name == "Biology");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department();

            var result = _controller.Create(dept);
            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit (GET) ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var result = _controller.Edit(deptId) as ViewResult;
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(deptId, model.DepartmentID);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Edit (POST) ---

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            var dept = _context.Departments.AsNoTracking().First();
            dept.Name = "Updated Department";

            var result = _controller.Edit(dept);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = _context.Departments.AsNoTracking().First();

            var result = _controller.Edit(dept);
            Assert.IsType<ViewResult>(result);
        }

        // --- Delete (GET) ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var result = _controller.Delete(deptId) as ViewResult;
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(deptId, model.DepartmentID);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed (POST) ---

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            // Create a standalone department to delete cleanly
            var dept = new Department
            {
                Name = "ToDelete",
                Budget = 100000m,
                StartDate = DateTime.Today
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(dept.DepartmentID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.DoesNotContain(_context.Departments, d => d.DepartmentID == dept.DepartmentID);
        }
    }
}

