using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelper.CreateSeededContext();
            _controller = new InstructorsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
        }

        public void Dispose()
        {
            _controller.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.Equal(5, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                .First(i => i.CourseAssignments.Any());

            var result = _controller.Index(instructor.ID, null) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);

            Assert.NotNull(model.Courses);
            Assert.True(model.Courses.Any());
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            var instructor = _context.Instructors
                .Include(i => i.CourseAssignments)
                    .ThenInclude(ca => ca.Course)
                        .ThenInclude(c => c.Enrollments)
                .First(i => i.CourseAssignments.Any(ca => ca.Course.Enrollments.Any()));

            var courseWithEnrollments = instructor.CourseAssignments
                .First(ca => ca.Course.Enrollments.Any()).Course;

            var result = _controller.Index(instructor.ID, courseWithEnrollments.CourseID) as ViewResult;
            var model = Assert.IsType<InstructorIndexData>(result.Model);

            Assert.NotNull(model.Enrollments);
            Assert.True(model.Enrollments.Any());
        }

        [Fact]
        public void Index_InstructorsAreSortedByLastName()
        {
            var result = _controller.Index(null, null) as ViewResult;
            var model = result.Model as InstructorIndexData;
            var names = model.Instructors.Select(i => i.LastName).ToList();
            var sorted = names.OrderBy(n => n).ToList();
            Assert.Equal(sorted, names);
        }

        // --- Details ---

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Details(instructorId) as ViewResult;
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructorId, model.ID);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- Create (GET) ---

        [Fact]
        public void Create_Get_ReturnsViewWithNewInstructor()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.Empty(model.CourseAssignments);
        }

        [Fact]
        public void Create_Get_PopulatesAssignedCourseData()
        {
            _controller.Create();
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Create (POST) ---

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 15)
            };

            var result = _controller.Create(instructor, null);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_SavesToDatabase()
        {
            var instructor = new Instructor
            {
                LastName = "SavedInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 15)
            };

            _controller.Create(instructor, null);
            Assert.Contains(_context.Instructors, i => i.LastName == "SavedInstructor");
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_CreatesCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "CourseInstructor",
                FirstMidName = "Test",
                HireDate = new DateTime(2020, 1, 15)
            };

            var courseIds = _context.Courses.Take(2).Select(c => c.CourseID.ToString()).ToArray();
            _controller.Create(instructor, courseIds);

            var saved = _context.Instructors
                .Include(i => i.CourseAssignments)
                .Single(i => i.LastName == "CourseInstructor");
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                HireDate = DateTime.Today
            };

            var result = _controller.Create(instructor, null);
            Assert.IsType<ViewResult>(result);
        }

        // --- Edit (GET) ---

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Edit(instructorId) as ViewResult;
            Assert.NotNull(result);
            Assert.IsType<Instructor>(result.Model);
        }

        // --- Delete (GET) ---

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsView()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Delete(instructorId) as ViewResult;
            var model = Assert.IsType<Instructor>(result.Model);
            Assert.Equal(instructorId, model.ID);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(99999);
            Assert.IsType<NotFoundResult>(result);
        }

        // --- DeleteConfirmed (POST) ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Create a standalone instructor to delete
            var instructor = new Instructor
            {
                LastName = "ToDelete",
                FirstMidName = "Test",
                HireDate = DateTime.Today,
                OfficeAssignment = new OfficeAssignment { Location = "TempOffice" }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(instructor.ID);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.DoesNotContain(_context.Instructors, i => i.ID == instructor.ID);
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            // Create instructor that is a department administrator
            var instructor = new Instructor
            {
                LastName = "AdminToDelete",
                FirstMidName = "Test",
                HireDate = DateTime.Today,
                OfficeAssignment = new OfficeAssignment { Location = "Office" }
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000m,
                StartDate = DateTime.Today,
                InstructorID = instructor.ID
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            _controller.DeleteConfirmed(instructor.ID);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

