using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.Single();
            Assert.Equal("Test", retrieved.LastName);
            Assert.Equal("Student", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var instructor = new Instructor
            {
                LastName = "Test",
                FirstMidName = "Instructor",
                HireDate = DateTime.Today
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.Single();
            Assert.Equal("Test", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000m,
                StartDate = DateTime.Today
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 9999,
                Title = "TestCourse",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.Include(c => c.Department).Single();
            Assert.Equal("TestCourse", retrieved.Title);
            Assert.Equal("TestDept", retrieved.Department.Name);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 200000m,
                StartDate = new DateTime(2020, 1, 1)
            };

            context.Departments.Add(dept);
            context.SaveChanges();

            var retrieved = context.Departments.Single();
            Assert.Equal("TestDept", retrieved.Name);
            Assert.Equal(200000m, retrieved.Budget);
        }

        [Fact]
        public void CanCreateEnrollmentWithRelationships()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var student = new Student
            {
                LastName = "EnrollTest",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Today
            };
            context.Students.Add(student);

            var dept = new Department
            {
                Name = "Dept",
                Budget = 100000m,
                StartDate = DateTime.Today
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1111,
                Title = "Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            var retrieved = context.Enrollments
                .Include(e => e.Student)
                .Include(e => e.Course)
                .Single();
            Assert.Equal("EnrollTest", retrieved.Student.LastName);
            Assert.Equal("Course", retrieved.Course.Title);
            Assert.Equal(Grade.A, retrieved.Grade);
        }

